}

use std::pin::Pin;

fn takes_unpin<T: Unpin>(val: Pin<&mut T>) {
    // T is Unpin, so we can safely get &mut T
    let inner: &mut T = Pin::into_inner(val);
    drop(inner);
}

// i32 is Unpin, so this works:
fn main() {
    let mut x = 42;
    let pinned = Pin::new(&mut x);
    takes_unpin(pinned);
}

